var data=msg.payload;
var obj=data.object||{};
msg.payload=[{measurement:'sensors',tags:{device:data.deviceInfo?data.deviceInfo.devEui:'unknown',name:data.deviceInfo?data.deviceInfo.deviceName:'unknown'},fields:{temperature:obj.temperatura||obj.temperature||0,humidity:obj.humedad_aire||obj.humidity||0,soil:obj.humedad_suelo||obj.soil||0,battery_mv:obj.bateria_mv||0,battery_pct:obj.bateria_pct||0},timestamp:new Date()}];
return msg;

const key='NASA_FIRMS_KEY';
const days=msg.req.query.days||1;
const bbox=msg.req.query.bbox||'1.5,41.2,2.5,41.7';
const url=`https://firms.modaps.eosdis.nasa.gov/api/area/csv/${key}/VIIRS_SNPP_NRT/${bbox}/${days}`;
msg.url=url;
return msg;

var lat=msg.req.query.lat||'41.45';
var lng=msg.req.query.lng||'2.18';
var end=new Date();end.setDate(end.getDate()-2);
var start=new Date();start.setDate(start.getDate()-30);
function fmt(d){return d.getFullYear()+String(d.getMonth()+1).padStart(2,'0')+String(d.getDate()).padStart(2,'0');}
msg.url='https://power.larc.nasa.gov/api/temporal/daily/point?parameters=T2M,T2M_MAX,T2M_MIN,RH2M,WS10M,ALLSKY_SFC_SW_DWN&community=RE&longitude='+lng+'&latitude='+lat+'&start='+fmt(start)+'&end='+fmt(end)+'&format=JSON';
return msg;

var lat=msg.req.query.lat||'41.45';
var lng=msg.req.query.lng||'2.18';
msg.url='https://api.open-meteo.com/v1/forecast?latitude='+lat+'&longitude='+lng+'&current=temperature_2m,relative_humidity_2m,wind_speed_10m,wind_direction_10m,precipitation,weather_code,apparent_temperature&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,wind_speed_10m_max&timezone=Europe/Madrid&forecast_days=7';
return msg;

var lat=msg.req.query.lat||'41.45';
var lng=msg.req.query.lng||'2.18';
msg.url='https://api.openaq.org/v3/locations?coordinates='+lat+','+lng+'&radius=25000&limit=10';
msg.headers={'X-API-Key':'OPENAQ_API_KEY'};
return msg;

var points=[];
for(var lat=41.1;lat<=41.9;lat+=0.13){for(var lng=1.6;lng<=2.8;lng+=0.17){points.push({lat:lat.toFixed(2),lng:lng.toFixed(2)});}}
msg.url='https://api.open-meteo.com/v1/forecast?latitude='+points.map(p=>p.lat).join(',')+'&longitude='+points.map(p=>p.lng).join(',')+'&current=wind_speed_10m,wind_direction_10m&timezone=Europe/Madrid&forecast_days=1';
msg.points=points;
return msg;

var lat=msg.req.query.lat||'41.45';
var lng=msg.req.query.lng||'2.18';
var now=new Date();
var year=now.getFullYear();
var jan1=new Date(year,0,1);
var doy=Math.ceil((now.getTime()-jan1.getTime())/86400000);
var startDoy=Math.max(1,doy-64);
function pad(n){return String(n).padStart(3,'0');}
msg.url='https://modis.ornl.gov/rst/api/v1/MOD13Q1/subset?latitude='+lat+'&longitude='+lng+'&startDate=A'+year+pad(startDoy)+'&endDate=A'+year+pad(doy)+'&kmAboveBelow=0&kmLeftRight=0';
return msg;

if (msg.payload && msg.payload.datos) {
    msg.url = msg.payload.datos;
    return msg;
} else {
    msg.payload = JSON.stringify({error: 'no datos url'});
    return [null, msg];
}

try {
    const text = msg.payload;
    const d = JSON.parse(text);
    const pred = d[0].prediccion.dia[0];
    const now = new Date();
    const hora = String(now.getHours()).padStart(2,'0');
    const cel = pred.estadoCielo.find(x=>x.periodo===hora)||pred.estadoCielo[0];
    const temp = pred.temperatura.find(x=>x.periodo===hora)||pred.temperatura[0];
    const prec = pred.precipitacion.find(x=>x.periodo===hora)||pred.precipitacion[0];
    const humitat = pred.humedadRelativa.find(x=>x.periodo===hora)||pred.humedadRelativa[0];
    msg.payload = JSON.stringify({
        municipi: d[0].nombre, data: pred.fecha, hora: hora+'h',
        cel: cel?cel.descripcion:'-',
        temperatura: temp?temp.value+'°C':'-',
        precipitacion: prec?prec.value+' mm':'-',
        humitat: humitat?humitat.value+'%':'-'
    });
} catch(e) { msg.payload = JSON.stringify({error: e.message}); }
return msg;
